import tensorflow as tffrom tensorflow.keras import layersx = tf.random.normal([2, 3])print(x)# 构建模型class MyModel(tf.keras.Model):    def __init__(self):        super(MyModel, self).__init__()        self.layer1 = layers.Dense(3, activation='relu')        self.layer2 = layers.Dense(3, activation='relu')        self.layer3 = layers.Dense(1, activation='sigmoid')    def call(self, inputs):        h1 = self.layer1(inputs)        h2 = self.layer2(h1)        out = self.layer3(h2)        return out# 设置模型输入与输出model = MyModel()model.build(input_shape=(None, 3))model.summary()print(model(x))